import{_ as a,c as e,o as r,a1 as d}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"プラットフォーム統合: 複数のプロトコル接続 | Antigravity-Manager","description":"Antigravity Tools のプラットフォームプロトコル接続方法を学習します。OpenAI、Anthropic、Gemini など7種類のプロトコルの統一 API ゲートウェイ変換をサポートします。","frontmatter":{"title":"プラットフォーム統合: 複数のプロトコル接続 | Antigravity-Manager","sidebarTitle":"あなたの AI プラットフォームを接続","subtitle":"プラットフォーム統合: 複数のプロトコル接続","description":"Antigravity Tools のプラットフォームプロトコル接続方法を学習します。OpenAI、Anthropic、Gemini など7種類のプロトコルの統一 API ゲートウェイ変換をサポートします。","order":200},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/platforms/index.md"}'),o={name:"ja/lbjlaq/Antigravity-Manager/platforms/index.md"};function i(l,t,n,s,c,h){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="プラットフォームと統合" tabindex="-1">プラットフォームと統合 <a class="header-anchor" href="#プラットフォームと統合" aria-label="Permalink to &quot;プラットフォームと統合&quot;">​</a></h1><p>Antigravity Tools のコア能力は、複数の AI プラットフォームのプロトコルを統一されたローカル API ゲートウェイに変換することです。この章では各プロトコルの接続方法、互換性の境界、ベストプラクティスを詳細に紹介します。</p><h2 id="この章が含むもの" tabindex="-1">この章が含むもの <a class="header-anchor" href="#この章が含むもの" aria-label="Permalink to &quot;この章が含むもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>チュートリアル</th><th>説明</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI 互換 API</a></td><td><code>/v1/chat/completions</code> と <code>/v1/responses</code> の実装戦略、OpenAI SDK を無意識に接続可能にする</td></tr><tr><td><a href="./anthropic/">Anthropic 互換 API</a></td><td><code>/v1/messages</code> と Claude Code の重要な契約、思考連鎖、システムプロンプトなどのコア能力をサポート</td></tr><tr><td><a href="./gemini/">Gemini ネイティブ API</a></td><td><code>/v1beta/models</code> および Google SDK エンドポイント接続、<code>x-goog-api-key</code> 互換をサポート</td></tr><tr><td><a href="./imagen/">Imagen 3 画像生成</a></td><td>OpenAI Images パラメータ <code>size</code>/<code>quality</code> の自動マッピング、任意のアスペクト比をサポート</td></tr><tr><td><a href="./audio/">音声認識</a></td><td><code>/v1/audio/transcriptions</code> の制限と大きなペイロードの処理</td></tr><tr><td><a href="./mcp/">MCP エンドポイント</a></td><td>Web Search/Reader/Vision を呼び出し可能なツールとして公開する</td></tr><tr><td><a href="./cloudflared/">Cloudflared トンネル</a></td><td>ローカル API を安全にパブリックに暴露（デフォルトでは安全ではない）</td></tr></tbody></table><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推奨順序</p><ol><li><strong>まず使用するプロトコルを学ぶ</strong>：Claude Code を使用している場合、まず <a href="./anthropic/">Anthropic 互換 API</a> を見る；OpenAI SDK を使用している場合、まず <a href="./openai/">OpenAI 互換 API</a> を見る</li><li><strong>その後 Gemini ネイティブを学ぶ</strong>：Google SDK の直接接続方法を理解する</li><li><strong>必要に応じて拡張機能を学ぶ</strong>：画像生成、音声認識、MCP ツール</li><li><strong>最後にトンネルを学ぶ</strong>：パブリック暴露が必要な場合 <a href="./cloudflared/">Cloudflared トンネル</a> を見る</li></ol></div><p><strong>クイック選択</strong>：</p><table tabindex="0"><thead><tr><th>あなたのシーン</th><th>推奨先に見る</th></tr></thead><tbody><tr><td>Claude Code CLI を使用</td><td><a href="./anthropic/">Anthropic 互換 API</a></td></tr><tr><td>OpenAI Python SDK を使用</td><td><a href="./openai/">OpenAI 互換 API</a></td></tr><tr><td>Google 公式 SDK を使用</td><td><a href="./gemini/">Gemini ネイティブ API</a></td></tr><tr><td>AI 画像描画が必要</td><td><a href="./imagen/">Imagen 3 画像生成</a></td></tr><tr><td>音声文字起こしが必要</td><td><a href="./audio/">音声認識</a></td></tr><tr><td>インターネット検索/Web 閲覧が必要</td><td><a href="./mcp/">MCP エンドポイント</a></td></tr><tr><td>リモートアクセスが必要</td><td><a href="./cloudflared/">Cloudflared トンネル</a></td></tr></tbody></table><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">始める前に確認してください</p><ul><li><a href="./../start/installation/">インストールとアップグレード</a> を完了済み</li><li><a href="./../start/add-account/">アカウント追加</a> を完了済み</li><li><a href="./../start/proxy-and-first-client/">ローカルリバースプロキシ起動</a> を完了済み（少なくとも <code>/healthz</code> にアクセス可能）</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>この章を学習した後、次の学習を続けることができます：</p><ul><li><a href="./../advanced/">高度な設定</a>：モデルルーティング、クォータガバナンス、高可用性スケジューリングなどの高度な機能</li><li><a href="./../faq/">よくある質問</a>：401/404/429 などのエラーが発生したときのトラブルシューティングガイド</li></ul>',13)])])}const A=a(o,[["render",i]]);export{f as __pageData,A as default};
